def ConfForNight(text: number):
    global night1, BonnieAI, ChicaAI, FoxyAI, FreddyAI
    if GameRunning == 0:
        night1 = blockSettings.read_number("Night")
        if text == 1:
            BonnieAI = 0
            ChicaAI = 0
            FoxyAI = 0
            FreddyAI = 0
        elif text == 2:
            BonnieAI = 2
            ChicaAI = 1
            FoxyAI = 0
            FreddyAI = 0
        elif text == 3:
            BonnieAI = 3
            ChicaAI = 4
            FoxyAI = 2
            FreddyAI = 1
        elif text == 4:
            BonnieAI = 4
            ChicaAI = 6
            FoxyAI = 5
            FreddyAI = 2
        elif text == 5:
            BonnieAI = 7
            ChicaAI = 9
            FoxyAI = 8
            FreddyAI = 5
