def on_a_pressed():
    global LightsOn, is_looking_at_cams
    if GameRunning == 0:
        LightsOn = 0
        if is_looking_at_cams == 1:
            show_office()
            is_looking_at_cams = 0
            tiles.set_current_tilemap(tilemap("""
                level3
                """))
        else:
            show_cam_view()
            is_looking_at_cams = 1
controller.A.on_event(ControllerButtonEvent.PRESSED, on_a_pressed)

def FreddyMove():
    global AnimPosFreddy
    # Перевірка умови скримера
    if AnimPosFreddy == 1:
        AnimPosFreddy = 0
        OfficeDoorsCheck("Freddy")
    elif AnimPosFreddy == 2:
        AnimPosFreddy = 1
    elif AnimPosFreddy == 4:
        AnimPosFreddy = 2
def MoveAnim(text2: str):
    if GameRunning == 0:
        # Перевірка умови скримера
        if text2 == "Freddy":
            FreddyMove()
        elif text2 == "Chica":
            ChicaMove()
        elif text2 == "Bonnie":
            BonnieMove()
        elif text2 == "Foxy":
            FoxyMove()
