def OfficeDoorsCheck(text22: str):
    if GameRunning == 0:
        if text22 == "Freddy":
            Check("Freddy")
        elif text22 == "Bonnie":
            Check("Bonnie")
        elif text22 == "Chica":
            Check("Chica")
        elif text22 == "Foxy":
            Check("Foxy")
def Check(text3: str):
    global FreddyInOffice, BonnieInOffice, ChicaInOffice, FoxyInOffice
    if GameRunning == 0:
        if text3 == "Freddy":
            if door_closed == 1:
                FreddyInOffice = 1
            else:
                FreddyInOffice = 2
        elif text3 == "Bonnie":
            if door_closed == 1:
                BonnieInOffice = 1
            else:
                BonnieInOffice = 2
        elif text3 == "Chica":
            if door_closed == 1:
                ChicaInOffice = 1
            else:
                ChicaInOffice = 2
        elif text3 == "Foxy":
            if door_closed == 1:
                FoxyInOffice = 1
            else:
                FoxyInOffice = 2
